package pe.org.camaracomercioica.protestos.service;
import org.junit.jupiter.api.Test; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.Mock; import org.mockito.junit.jupiter.MockitoExtension; import org.springframework.mock.web.MockMultipartFile; import org.springframework.security.access.AccessDeniedException; import org.springframework.test.util.ReflectionTestUtils; import pe.org.camaracomercioica.protestos.model.*; import pe.org.camaracomercioica.protestos.repository.*; import java.util.Optional; import static org.assertj.core.api.Assertions.assertThatThrownBy; import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class UploadServiceTest { @Mock DocumentoRepository documentos;@Mock CargaExcelRepository cargas;@Mock SolicitudRepository solicitudes;@Mock UsuarioRepository usuarios;
 @Test void rechazaDocumentoSiEntidadNoEsPropietaria() throws Exception {var service=new UploadService(documentos,cargas,solicitudes,usuarios);ReflectionTestUtils.setField(service,"maxBytes",1024L);ReflectionTestUtils.setField(service,"location","./target/test-storage");var owner=new Usuario();owner.setEmail("owner@test.local");var s=new Solicitud();s.setSolicitante(owner);when(solicitudes.findById(1L)).thenReturn(Optional.of(s));var f=new MockMultipartFile("file","doc.pdf","application/pdf","pdf".getBytes());assertThatThrownBy(()->service.documento(1L,f,"other@test.local",false)).isInstanceOf(AccessDeniedException.class);verify(documentos,never()).save(any());}
}
